import{_ as e,c as o,o as t}from"./chunks/framework.Bp57zsBi.js";const p=JSON.parse(`{"title":"Introduction","description":"","frontmatter":{"layout":"NeoNephosIntroductionThemeComponent","title":"Introduction","sidebar":false,"aside":false,"hero":{"name":"About NeoNephos","subtitle":"We are dedicated to advancing open source projects that align with the strategic objectives of the EU's IPCEI-CIS.","descriptionPart1":"On March 31, 2025, the Linux Foundation Europe officially announced the launch of the non-profit open source NeoNephos Foundation. The launch was followed by a KubeCon+CloudNativeCon 2025 <a href=\\"https://youtu.be/57koOOg0f5M?t=657\\">Keynote Walk-On announcement</a> in April, presents the culmination of a long phase of preparation and deliberation among the initial founding members: SAP SE, Deutsche Telekom AG, STACKIT, Clyso GmbH, Cyberus Technology, TNO-ECOFED, 23 Technologies GmbH, Elastx and x-cellent technologies GmbH.","descriptionPart2":"To fully appreciate the significance of our foundation requires a brief elaboration of the situational context. <a href=\\"https://www.consultancy.eu/news/10650/european-iaas-and-paas-cloud-market-to-double-by-2028\\">For years, the European cloud services market has grown significantly</a>. However, domestic providers have struggled to fully benefit from the increased market size of the cloud.</a> Key reasons can be traced back to fragmentation of cloud infrastructure due to a lack of standards and connectivity. These conditions favor already entrenched, non-domestic players in the market, inducing vendor lock in and ultimately reducing choice for customers. Since conditions are unlikely to be resolved by pure market dynamics alone, on <a href=\\"https://competition-policy.ec.europa.eu/state-aid/ipcei/approved-ipceis/cloud_en\\">December 5, 2023, the European Commission approved</a> the initiation of an Important Project of Common European Interest – Next Generation Cloud Infrastructures and Services (IPCEI – CIS). This initiative allows the distribution of state aid of participating member states to private companies and organizations, with the goal of co-financing efforts which lay the groundwork for seamless usage of cloud and edge services across European providers.","descriptionPart3":"Under this so called Multi-Provider-Cloud-Edge-Continuum, <a href=\\"https://www.8ra.com/wp-content/uploads/8ra_Supervisory-Board_Mission-Document.pdf\\">positioned under the trademark 8ra</a>, data shall be processed locally where it is produced, reducing latency, environmental burden, and data transfer costs by combining cloud and edge resources from multiple sovereign providers. Once established, organizations will no longer be tied to a single provider and can run cloud-native applications wherever they choose. <a href=\\"https://apeirora.eu/\\">The Apeiro Reference Architecture by SAP</a> is one of the projects under development within the framework of the IPCEI. But to provide a spillover effect of ApeiroRA’s results long past the time limited nature of an IPCEI, a shared development vehicle was needed, allowing different organizations to work together and securing the investments of the initial IPCEI for the long term.","descriptionPart4":"The Linux Foundation Europe was found to be a good match to long-term secure the investments put into ApeiroRA and co-develop new projects with additional partners under the same vision. Today, NeoNephos hosts more than 11 projects, with many more to come, from a diverse array of different partners and members. Each project is fully donated to the foundation, with all trademarks and assets belonging to the Linux Foundation Europe. NeoNephos provides a sustainable, shared development model for projects of the cloud-edge continuum and offers collaborative potential for higher adoption. By being open to hosting projects from other industry players and the community at large, the foundation provides a nurturing environment for any project sharing the goal of an open, enterprise-hardened, multi provider cloud-to-edge continuum."},"tilesHeading":"Learn more!","tiles":[{"title":"IPCEI-CIS","details":"Learn more about IPCEI-CIS, 8ra and similar initiatives!","linkText":"Explore IPCEI-CIS","linkUrl":"https://competition-policy.ec.europa.eu/state-aid/ipcei/approved-ipceis/cloud_en"},{"title":"ApeiroRA","details":"Learn more about SAP's entry to the IPCEI-CIS.","linkText":"Explore ApeiroRA","linkUrl":"https://apeirora.eu"},{"title":"Linux Foundation Europe","details":"The Linux Foundation Europe (LFEU) is our umbrella organization.","linkText":"Explore LFEU","linkUrl":"https://linuxfoundation.eu"}]},"headers":[],"relativePath":"introduction.md","filePath":"introduction.md"}`),n={name:"introduction.md"};function a(i,r,s,d,l,c){return t(),o("div")}const h=e(n,[["render",a]]);export{p as __pageData,h as default};
